+	// â”€â”€ Private: connect JSON-RPC over stdio â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
+
+	private async connectViaStdio(): Promise<void> {
